+fn sample_mean_variance(samples: &[f64]) -> (f64, f64) {
+    let n = samples.len() as f64;
+    let mean = samples.iter().sum::<f64>() / n;
+    let variance = samples
+        .iter()
+        .map(|sample| {
+            let diff = sample - mean;
+            diff * diff
+        })
+        .sum::<f64>()
+        / n;
+    (mean, variance)
+}
