+                } else if x >= high {
+                    1.0
+                } else {
+                    (x - low) / (high - low)
+                }
+            }))
+        }
+        "normal" => {
+            let mean = case.param_a;
+            let std_dev = case.param_b;
+            if !(mean.is_finite() && std_dev.is_finite() && std_dev > 0.0) {
+                return Err("normal ks parameters require finite std_dev > 0".to_string());
+            }
