+            }))
+        }
+        "power" => {
+            let alpha = case.param_a;
+            if !(alpha.is_finite() && alpha > 0.0) {
+                return Err("power ks parameters require finite alpha > 0".to_string());
+            }
+            Ok(Box::new(move |x| {
